module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green
);

localparam GREEN_TIME = 60;
localparam YELLOW_TIME = 5;
localparam RED_TIME = 10;

reg [5:0] state;
reg [5:0] next_state;
reg [5:0] timer;

localparam GREEN = 3'd0;
localparam YELLOW = 3'd1;
localparam RED = 3'd2;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= GREEN;
        timer <= 0;
    end else begin
        state <= next_state;
        if (timer > 0) begin
            timer <= timer - 1;
        end
    end
end

always @(*) begin
    next_state = state;
    red = 1'b0;
    yellow = 1'b0;
    green = 1'b0;

    case (state)
        GREEN: begin
            green = 1'b1;
            if (timer == 0) begin
                timer = GREEN_TIME;
                next_state = YELLOW;
            end
        end
        YELLOW: begin
            yellow = 1'b1;
            if (timer == 0) begin
                timer = YELLOW_TIME;
                next_state = RED;
            end
        end
        RED: begin
            red = 1'b1;
            if (timer == 0) begin
                timer = RED_TIME;
                next_state = GREEN;
            end
            else if (pass_request && timer > 10) begin
                timer = 10;
                next_state = GREEN;
            end
        end
    endcase
end

endmodule
